examples.code:
-- Create a new database user
CREATE USER app_user IDENTIFIED BY 'SecurePass123';

-- Grant system privileges
GRANT CREATE SESSION TO app_user;
GRANT CREATE TABLE TO app_user;
GRANT CREATE VIEW TO app_user;

-- Grant object privileges on specific tables
GRANT SELECT, INSERT, UPDATE ON employees TO app_user;
GRANT SELECT ON departments TO app_user;

-- Create a role and assign privileges
CREATE ROLE analyst_role;
GRANT SELECT ON employees TO analyst_role;
GRANT SELECT ON salaries TO analyst_role;
GRANT analyst_role TO app_user;

-- Revoke privileges when needed
REVOKE INSERT ON employees FROM app_user;

-- Drop user (cascade removes all objects)
-- DROP USER app_user CASCADE;
